const { KnockManagement } = require("@knocklabs/mgmt");

const runId = process.env.ZEALT_RUN_ID;
const serviceToken = process.env.KNOCK_SERVICE_TOKEN;

const knock = new KnockManagement(serviceToken);

async function provision() {
  const workflowKey = `popover-demo-${runId}`;

  console.log(`Provisioning workflow: ${workflowKey}`);

  try {
    const workflow = await knock.workflows.upsert(workflowKey, {
      name: `Popover Demo ${runId}`,
      active: true,
      steps: [
        {
          type: "channel",
          channel_key: "in-app",
          template: {
            body: "{{ data.body }}",
          },
        },
      ],
    });

    console.log("Workflow provisioned successfully");

    // Activate the workflow in development environment
    // Upsert usually handles this if active: true is passed, 
    // but let's be sure.

  } catch (error) {
    console.error("Error provisioning workflow:", error);
    process.exit(1);
  }
}

provision();

